import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as i,e as t}from"./app-b1d8d005.js";const r="/assets/image-20240127220939428-c19dd06c.png",c="/assets/image-20240127221038489-3b17a752.png",n="/assets/image-20240127221153255-b89c819a.png",s={},o=t('<h1 id="蜡烛图与艾略特波浪理论" tabindex="-1"><a class="header-anchor" href="#蜡烛图与艾略特波浪理论" aria-hidden="true">#</a> 蜡烛图与艾略特波浪理论</h1><p>应用艾略特波浪理论的技术分析师为数众多，广泛分布在各种市场领域内。这一理论既适用于日内价格图表，也适用于以年为时间单位的超长期图表。在本章，我们只准备对艾略特波浪理论作一点粗浅的入门性介绍。如果详细介绍艾略特波浪理论的市场分析方法，恐怕非得专门写一本书不可。</p><h2 id="艾略特波浪理论的基本概念" tabindex="-1"><a class="header-anchor" href="#艾略特波浪理论的基本概念" aria-hidden="true">#</a> 艾略特波浪理论的基本概念</h2><figure><img src="'+r+'" alt="image-20240127220939428" tabindex="0" loading="lazy"><figcaption>image-20240127220939428</figcaption></figure><p>艾略特波浪理论是R.N.艾略特在本世纪初发现的。他从市场各个方面的特性中注意到，价格运动是通过下述基本过程形成的：先是五浪上涨，然后跟着调整性的三浪下跌。如图16.1所示，上述八浪组成了一个完整的市场周期。其中，1浪、3浪、5浪称为主浪（也称推进浪），2浪和4浪称为调整浪（也称次浪）。虽然在图16.1中，艾略特波浪的数浪情况反映出一个上涨的市场，但是，同样的概念也适用于下跌的市场。于是，在下降趋势的市场上，主浪的方向将是向下倾斜的，而调整浪则向上倾斜，与主要趋势方向相反。艾略特另一方面的重大贡献是，将菲波纳奇数列引入了市场预测研究。因为菲波纳奇比数可以用来推算下一浪的价格目标，所以数浪技术与菲波纳奇比数是相辅相成的。举例来说，我们可以将1浪的高度乘以1.618，由此推测3浪的高度；4浪可能将3浪的运动幅度往回调整38.2%，或者50%；如此等等。</p><h2 id="艾略特波浪理论与蜡烛图" tabindex="-1"><a class="header-anchor" href="#艾略特波浪理论与蜡烛图" aria-hidden="true">#</a> 艾略特波浪理论与蜡烛图</h2><p>本章所要说明的是，从蜡烛图上能够取得旁证，有助于确认艾略特波浪的终止点。在实际交易中，最重要的波浪是3浪和5浪。3浪通常是最强劲的一段行情；而在5浪的顶部，我们必须及时掉转头寸方向。在以下各例的数浪中，我从我的同事约翰・甘比诺那里获益良多，他对艾略特理论有专门的研究。艾略特波浪的数浪分析具有主观性《至少在波浪最终完成之前是这样的），因此，以下的数浪结论同其它分析者也许不一定相同。</p><figure><img src="'+c+'" alt="image-20240127221038489" tabindex="0" loading="lazy"><figcaption>image-20240127221038489</figcaption></figure><p>如图16.2（a）所示，我们在本例中标数出一个五浪结构，以下将对每一浪作一番分析。推进浪①是从2月下旬的乌云盖顶形态开始的。3月中旬，出现了一个孕线形态，于是推进浪①结束。这一孕线形态出现，意昧着之前市场向下的压力正在消退。随后，形成了一段向上反弹行情。这段反弹行情就是调整浪②，它结束于另一个小规模的乌云盖顶形态。推进浪③构成了主要的下跌过程。这段价格运动的范围，可以通过一个菲波纳奇比数和1浪的高度推算出来。估算的结果是，③浪的价格目标在17.60美元。在17.60美元的水平上，我们期望市场形成某种蜡烛图信号，以验证我们标数的③浪的底部。这一信号发生在4月11日。关于4月11日价格变化的详细情况，请看图16.2（b），这是上述原油市场的日内图表。</p><p>在4月11日的头一个小时内，原油市场从前一天的收市价起，向下狂泻了1美元。在这一时刻看来，这场抛售行情似乎还未终结。但是后来，出现了一些有趣的价格变化。这场抛售行情在17.35美元处突然中断--这与艾略特理论预测的17.60美元非常接近。其次，在这张小时线图表上[请看图16.2（b）]，随着这轮抛售行情的结束，当天的头一小时最后形成了一根经典的锤子线。在这个潜在的看涨指标之后，立即出现了一系列坚挺的长长白色实体。在这张小时图表上，这根看涨的锤子线，以及之后的这些白色蜡烛线，验证了我们标数的③浪的底部。在上面的日蜡烛线图上，也提供了一个底部反转信号。4月10日和11日的价格变化組成了一个刺透形态。接下来，我们预期市场将产生4浪的上涨行情。</p><p>根据艾略特波浪理论，④浪应当构成上涨行情。但是④浪的顶部不应当向上超过1浪的底部。在这个实例中，这个水平大约为19.95美元。当市场接近这一水平的时候，我们希望看到看跌的蜡烛图线索。结果，这种情况果然出现了。5月14日和15日，市场在20美元之下形成了一个十字孕线形态，以及一个平头顶部形态。于是，上涨过程陷入停顿，④浪达到了顶部。</p><p>有趣的是，如果我们将④浪进一步细分为（a）、（b）、（c）成分浪，则它们与蜡烛图信号相互印证的情形就更加一目了然了。在（a）处，是一根流星线，它的高点止于4月初出现的窗口的水平上。在（b）处，一个启明星形态标志訾市场底部的形成。成分浪（c）浪的顶部也是④浪的顶部，此处出现的看跌蜡烛图指标计有：一个十字孕线形态、一个平头顶部形态。</p><figure><img src="'+n+'" alt="image-20240127221153255" tabindex="0" loading="lazy"><figcaption>image-20240127221153255</figcaption></figure><p>如图16.3所示，⑤浪推进浪的方向向下，它们是从1989年12月的100.16美元的水平开始的。波浪标数的情况如图所示。在①浪<br> 的底部，市场形成了一个孕线形态。在②浪的顶部，形成了一个乌云盖顶形态。③浪底部没有出现蜡烛图指标。④浪的顶部构成了一个孕线形态。在本例的艾略特五浪形态中，最吸人的地方是其第⑤浪，即最后一个下跌浪。我们根据第③浪的高度和一个菲波纳奇比数，推导出了第五浪的价格目标。由此得到的目标价格水平为88.08美元。4月底，这段下跌行情的低点位于88.07美元。在这个低点处，蜡烛图发出了一组强烈的看涨信号：一个平头底部形态，以及这个平头底部形态内部的两根十字线。交易量的变化也验证了这一底部的形成。请参见图15.1，在那里，我们曾经详细讨论了在这个低点处蜡烛图与交易量相互印证的具体情况。</p>',14),_=[o];function p(d,g){return e(),i("div",null,_)}const m=a(s,[["render",p],["__file","12-蜡烛图与艾略特波浪理论.html.vue"]]);export{m as default};
